function fitness(operator, data) {
  var accuracy = 0;
  data.forEach(triple => {
    var predicted = operator.apply(triple.before, triple.event);
    accuracy += distance(predicted, triple.after);
  });

  var parsimony = operator.tree_size(); // penalize complexity
  var composability = test_composition(operator); // does it chain cleanly?

  return accuracy - 0.1*parsimony + 0.2*composability;
}

function ATRANS_evolved(obj, from_entity, to_entity) {
  // SUCCESS RATE: Beta(9, 1) — learned from data!
  var p_success = sample(Beta({a: 9, b: 1}));

  if (sample(Bernoulli({p: p_success}))) {
    // MAGNITUDE: Delta (deterministic) — always transfer full value
    var delta = 1.0;

    return {
      from: {...from_entity, possession: from_entity.possession - delta*obj.value},
      to: {...to_entity, possession: to_entity.possession + delta*obj.value}
    };
  } else {
    // Transfer failed — return unchanged states
    return {from: from_entity, to: to_entity};
  }
}

// Probabilistic program: model a gift-giving scenario
var model = Infer({method: 'MCMC'}, function() {
  var initial_state = {Alice: {books: 5}, Bob: {books: 2}};

  // ATRANS is a discovered operator with learned parameters
  var result = ATRANS_evolved({value: 1}, initial_state.Alice, initial_state.Bob);

  // Condition on observed outcome
  observe(Delta({v: result.to.books}), 3); // Bob ends with 3 books

  // Infer: did the transfer succeed?
  return result.from.books === 4; // true if it worked
});

expectation(model); // ≈ 0.9 (high confidence it succeeded)

